class Solution:
    def reversePrefix(self, word, ch):
        idx = -1
        for i, c in enumerate(word):
            if c == ch:
                idx = i
                break
        if idx == -1:
            return word
        prefix = list(word[:idx + 1])
        prefix.reverse()
        return ''.join(prefix) + word[idx + 1:]

